theme.custom_css_code:
.monster-wrap{
  width:100%;
  background:transparent;
  font-family:Arial,sans-serif;
  color:#ffffff;
}
.monster-card{
  background:#1c1d20;
  border:1px solid rgba(255,255,255,0.1);
  border-radius:20px;
  padding:24px;
  box-sizing:border-box;
  box-shadow:0 10px 30px rgba(0,0,0,0.28);
}
.monster-table-wrap{
  width:100%;
  overflow-x:auto;
}
.monster-table{
  width:100%;
  min-width:640px;
  border-collapse:collapse;
}
.monster-table td{
  padding:14px 16px;
  border-bottom:1px solid rgba(255,255,255,0.08);
  font-size:15px;
  line-height:1.45;
}
.monster-table tr:last-child td{
  border-bottom:none;
}
.monster-table td:first-child{
  width:42%;
  color:rgba(255,255,255,0.68);
}
.monster-table td:last-child{
  color:#ffffff;
  font-weight:600;
}
.monster-chart{
  width:100%;
}
.monster-chart-title{
  font-size:14px;
  line-height:1.4;
  letter-spacing:0.08em;
  text-transform:uppercase;
  color:rgba(255,255,255,0.62);
  margin:0 0 18px;
}
.monster-bars{
  display:grid;
  gap:14px;
}
.monster-bar-row{
  display:grid;
  grid-template-columns:140px 1fr 52px;
  gap:14px;
  align-items:center;
}
.monster-label{
  font-size:14px;
  color:#ffffff;
  white-space:nowrap;
}
.monster-track{
  width:100%;
  height:14px;
  background:rgba(255,255,255,0.08);
  border-radius:999px;
  overflow:hidden;
  position:relative;
}
.monster-fill{
  height:100%;
  border-radius:999px;
  background:linear-gradient(90deg,#6be7ff 0%,#8a7dff 50%,#ff6bd6 100%);
}
.monster-value{
  text-align:right;
  font-size:14px;
  color:rgba(255,255,255,0.78);
}
.monster-grid-2{
  display:grid;
  grid-template-columns:1fr;
  gap:24px;
}
.monster-radar-wrap{
  display:flex;
  justify-content:center;
  align-items:center;
}
.monster-legend{
  display:grid;
  gap:10px;
  margin-top:20px;
}
.monster-legend-item{
  display:flex;
  align-items:center;
  gap:10px;
  font-size:14px;
  color:#ffffff;
}
.monster-dot{
  width:12px;
  height:12px;
  border-radius:50%;
  flex:0 0 12px;
}
.monster-dot-a{
  background:#7ae4ff;
}
.monster-dot-b{
  background:#ff7bd8;
}
@media (min-width:768px){
  .monster-card{
    padding:28px;
  }
  .monster-grid-2{
    grid-template-columns:1.1fr 0.9fr;
    align-items:center;
  }
}
@media (max-width:640px){
  .monster-card{
    padding:18px;
    border-radius:16px;
  }
  .monster-bar-row{
    grid-template-columns:1fr;
    gap:8px;
  }
  .monster-value{
    text-align:left;
  }
  .monster-chart-title{
    margin-bottom:14px;
  }
}
